from __future__ import annotations

import datetime
from dataclasses import dataclass
from enum import Enum, auto


@dataclass(frozen=True)
# generated by AI in Github cloud
class Greeting:
    """Immutable value object holding a greeting message."""

    recipient: str
    message: str

    def __post_init__(self) -> None:
        if not self.recipient or not self.recipient.strip():
            raise ValueError("recipient must not be blank")
        if not self.message or not self.message.strip():
            raise ValueError("message must not be blank")

    def formatted(self) -> str:
        """Return a fully-formatted greeting string."""
        return (
            "╔══════════════════════════════╗\n"
            f"║  {self.message}, {self.recipient}!  ║\n"
            "╚══════════════════════════════╝\n"
        )


class TimeOfDay(Enum):
    """Simple enum representing the time of day."""

    MORNING = auto()
    AFTERNOON = auto()
    EVENING = auto()

    @staticmethod
    def of(hour: int) -> "TimeOfDay":
        """Map an hour (0-23) to the appropriate TimeOfDay."""
        if hour < 12:
            return TimeOfDay.MORNING
        if hour < 17:
            return TimeOfDay.AFTERNOON
        return TimeOfDay.EVENING


def season_of(month: int) -> str:
    """Return the meteorological season for the given month number (1-12)."""
    if month in (12, 1, 2):
        return "Winter"
    if month in (3, 4, 5):
        return "Spring"
    if month in (6, 7, 8):
        return "Summer"
    return "Autumn"


def main() -> None:
    """Entry point – prints a greeting and date/season info to stdout."""
    today = datetime.date.today()
    hour = datetime.datetime.now().hour
    time_of_day = TimeOfDay.of(hour)

    salutation = {
        TimeOfDay.MORNING: "Good morning",
        TimeOfDay.AFTERNOON: "Good afternoon",
        TimeOfDay.EVENING: "Good evening",
    }[time_of_day]

    greeting = Greeting("World", salutation)
    print(greeting.formatted(), end="")

    import sys
    info = (
        f"Python version : {sys.version.split()[0]}\n"
        f"Today's date   : {today} ({season_of(today.month)})\n"
    )
    print(info, end="")


if __name__ == "__main__":
    main()
